197	    private <T extends ApiCommand, R> CompletableFuture<R> submitCommandAsync(final EventTranslatorOneArg<OrderCommand, T> translator,
198	                                                                              final T apiCommand,
199	                                                                              final Function<OrderCommand, R> responseTranslator) {
200	        final CompletableFuture<R> future = new CompletableFuture<>();
201	
202	        ringBuffer.publishEvent(
203	                (cmd, seq, apiCmd) -> {
204	                    translator.translateTo(cmd, seq, apiCmd);
205	                    promises.put(seq, orderCommand -> future.complete(responseTranslator.apply(orderCommand)));
206	                },
207	                apiCommand);
208	
209	        return future;
210	    }
