212	    private CompletableFuture<CommandResultCode> submitPersistCommandAsync(final ApiPersistState apiCommand) {
213	
214	        final CompletableFuture<CommandResultCode> future1 = new CompletableFuture<>();
215	        final CompletableFuture<CommandResultCode> future2 = new CompletableFuture<>();
216	
217	        publishPersistCmd(apiCommand, (seq1, seq2) -> {
218	            promises.put(seq1, cmd -> future1.complete(cmd.resultCode));
219	            promises.put(seq2, cmd -> future2.complete(cmd.resultCode));
220	        });
221	
222	        return future1.thenCombineAsync(future2, CommandResultCode::mergeToFirstFailed);
223	    }
