297	    private void publishBinaryData(final OrderCommandType cmdType,
298	                                   final WriteBytesMarshallable data,
299	                                   final int dataTypeCode,
300	                                   final int transferId,
301	                                   final long timestamp,
302	                                   final LongConsumer endSeqConsumer) {
303	
304	        final long[] longsArrayData = SerializationUtils.bytesToLongArrayLz4(
305	                lz4Compressor,
306	                BinaryCommandsProcessor.serializeObject(data, dataTypeCode),
307	                LONGS_PER_MESSAGE);
308	
309	        final int totalNumMessagesToClaim = longsArrayData.length / LONGS_PER_MESSAGE;
310	
311	//        log.debug("longsArrayData[{}] n={}", longsArrayData.length, totalNumMessagesToClaim);
312	
313	        // max fragment size is quarter of ring buffer
314	        final int batchSize = ringBuffer.getBufferSize() / 4;
315	
316	        int offset = 0;
317	        boolean isLastFragment = false;
318	        int fragmentSize = batchSize;
319	
320	        do {
321	
322	            if (offset + batchSize >= totalNumMessagesToClaim) {
323	                fragmentSize = totalNumMessagesToClaim - offset;
324	                isLastFragment = true;
325	            }
326	
327	            publishBinaryMessageFragment(cmdType, transferId, timestamp, endSeqConsumer, longsArrayData, fragmentSize, offset, isLastFragment);
328	
329	            offset += batchSize;
330	
331	        } while (!isLastFragment);
332	
333	    }
334	
335	    private void publishBinaryMessageFragment(OrderCommandType cmdType,
336	                                              int transferId,
337	                                              long timestamp,
338	                                              LongConsumer endSeqConsumer,
339	                                              long[] longsArrayData,
340	                                              int fragmentSize,
341	                                              int offset,
342	                                              boolean isLastFragment) {
343	
344	        final long highSeq = ringBuffer.next(fragmentSize);
345	        final long lowSeq = highSeq - fragmentSize + 1;
346	
347	//        log.debug("  offset*longsPerMessage={} longsArrayData[{}] n={} seq={}..{} lastFragment={} fragmentSize={}",
348	//                offset * LONGS_PER_MESSAGE, longsArrayData.length, fragmentSize, lowSeq, highSeq, isLastFragment, fragmentSize);
349	
350	        try {
351	            int ptr = offset * LONGS_PER_MESSAGE;
352	            for (long seq = lowSeq; seq <= highSeq; seq++) {
353	
354	                OrderCommand cmd = ringBuffer.get(seq);
355	                cmd.command = cmdType;
356	                cmd.userCookie = transferId;
357	                cmd.symbol = (isLastFragment && seq == highSeq) ? -1 : 0;
358	
359	                cmd.orderId = longsArrayData[ptr];
360	                cmd.price = longsArrayData[ptr + 1];
361	                cmd.reserveBidPrice = longsArrayData[ptr + 2];
362	                cmd.size = longsArrayData[ptr + 3];
363	                cmd.uid = longsArrayData[ptr + 4];
364	
365	                cmd.timestamp = timestamp;
366	                cmd.resultCode = CommandResultCode.NEW;
367	
368	//                log.debug("ORIG {}", String.format("f=%d word0=%X word1=%X word2=%X word3=%X word4=%X",
369	//                cmd.symbol, longArray[i], longArray[i + 1], longArray[i + 2], longArray[i + 3], longArray[i + 4]));
370	
371	//                log.debug("seq={} cmd.size={} data={}", seq, cmd.size, cmd.price);
372	
373	                ptr += LONGS_PER_MESSAGE;
374	            }
375	        } catch (final Exception ex) {
376	            log.error("Binary commands processing exception: ", ex);
377	
378	        } finally {
379	            if (isLastFragment) {
380	                // report last sequence before actually publishing data
381	                endSeqConsumer.accept(highSeq);
382	            }
383	            ringBuffer.publish(lowSeq, highSeq);
384	        }
385	    }
