387	    private void publishPersistCmd(final ApiPersistState api,
388	                                   final LongLongConsumer seqConsumer) {
389	
390	        long secondSeq = ringBuffer.next(2);
391	        long firstSeq = secondSeq - 1;
392	
393	        try {
394	            // will be ignored by risk handlers, but processed by matching engine
395	            final OrderCommand cmdMatching = ringBuffer.get(firstSeq);
396	            cmdMatching.command = OrderCommandType.PERSIST_STATE_MATCHING;
397	            cmdMatching.orderId = api.dumpId;
398	            cmdMatching.symbol = -1;
399	            cmdMatching.uid = 0;
400	            cmdMatching.price = 0;
401	            cmdMatching.timestamp = api.timestamp;
402	            cmdMatching.resultCode = CommandResultCode.NEW;
403	
404	            //log.debug("seq={} cmd.command={} data={}", firstSeq, cmdMatching.command, cmdMatching.price);
405	
406	            // sequential command will make risk handler to create snapshot
407	            final OrderCommand cmdRisk = ringBuffer.get(secondSeq);
408	            cmdRisk.command = OrderCommandType.PERSIST_STATE_RISK;
409	            cmdRisk.orderId = api.dumpId;
410	            cmdRisk.symbol = -1;
411	            cmdRisk.uid = 0;
412	            cmdRisk.price = 0;
413	            cmdRisk.timestamp = api.timestamp;
414	            cmdRisk.resultCode = CommandResultCode.NEW;
415	
416	            //log.debug("seq={} cmd.command={} data={}", firstSeq, cmdMatching.command, cmdMatching.price);
417	
418	            // short delay to reduce probability of batching both commands together in R1
419	        } finally {
420	            seqConsumer.accept(firstSeq, secondSeq);
421	            ringBuffer.publish(firstSeq, secondSeq);
422	        }
423	    }
