121	    public MatcherTradeEvent createBinaryEventsChain(final long timestamp,
122	                                                     final int section,
123	                                                     final NativeBytes<Void> bytes) {
124	
125	        long[] dataArray = SerializationUtils.bytesToLongArray(bytes, 5);
126	
127	        MatcherTradeEvent firstEvent = null;
128	        MatcherTradeEvent lastEvent = null;
129	        for (int i = 0; i < dataArray.length; i += 5) {
130	
131	            final MatcherTradeEvent event = newMatcherEvent();
132	
133	            event.eventType = MatcherEventType.BINARY_EVENT;
134	
135	            event.section = section;
136	            event.matchedOrderId = dataArray[i];
137	            event.matchedOrderUid = dataArray[i + 1];
138	            event.price = dataArray[i + 2];
139	            event.size = dataArray[i + 3];
140	            event.bidderHoldPrice = dataArray[i + 4];
141	
142	            event.nextEvent = null;
143	
144	//            log.debug("BIN EVENT: {}", event);
145	
146	            // attach in direct order
147	            if (firstEvent == null) {
148	                firstEvent = event;
149	            } else {
150	                lastEvent.nextEvent = event;
151	            }
152	            lastEvent = event;
153	        }
154	
155	        return firstEvent;
156	    }
