159	    public static NavigableMap<Integer, Wire> deserializeEvents(final OrderCommand cmd) {
160	
161	        final Map<Integer, List<MatcherTradeEvent>> sections = new HashMap<>();
162	        cmd.processMatcherEvents(evt -> sections.computeIfAbsent(evt.section, k -> new ArrayList<>()).add(evt));
163	
164	        NavigableMap<Integer, Wire> result = new TreeMap<>();
165	
166	        sections.forEach((section, events) -> {
167	            final long[] dataArray = events.stream()
168	                    .flatMap(evt -> Stream.of(
169	                            evt.matchedOrderId,
170	                            evt.matchedOrderUid,
171	                            evt.price,
172	                            evt.size,
173	                            evt.bidderHoldPrice))
174	                    .mapToLong(s -> s)
175	                    .toArray();
176	
177	            final Wire wire = SerializationUtils.longsToWire(dataArray);
178	
179	            result.put(section, wire);
180	        });
181	
182	
183	        return result;
184	    }
