186	    private MatcherTradeEvent newMatcherEvent() {
187	
188	        if (EVENTS_POOLING) {
189	            if (eventsChainHead == null) {
190	                eventsChainHead = eventChainsSupplier.get();
191	//            log.debug("UPDATED HEAD size={}", eventsChainHead == null ? 0 : eventsChainHead.getChainSize());
192	            }
193	            final MatcherTradeEvent res = eventsChainHead;
194	            eventsChainHead = eventsChainHead.nextEvent;
195	            return res;
196	        } else {
197	            return new MatcherTradeEvent();
198	        }
199	    }
