636	                takerUp.accounts.addToValue(spec.quoteCurrency, -fee);
637	                fees.addToValue(spec.quoteCurrency, fee);
638	            } else if (ev.eventType == MatcherEventType.REJECT || ev.eventType == MatcherEventType.REDUCE) {
639	                // for cancel/rejection only one party is involved
640	                takerSpr.pendingRelease(takerAction, ev.size);
641	            }
642	
643	            if (takerSpr.isEmpty()) {
644	                removePositionRecord(takerSpr, takerUp);
645	            }
646	        }
