import org.eclipse.collections.impl.list.mutable.primitive.LongArrayList;
import org.eclipse.collections.impl.map.mutable.primitive.LongObjectHashMap;

import java.util.function.BiConsumer;

/**
 * Primitive long-key sorted map backed by a hash table (O(1) point lookups)
 * and a sorted long[] array (cache-friendly ordered traversal).
 * <p>
 * Optimised for small-to-medium cardinality (order-book price buckets, typically <10k entries)
 * where array copying cost is lower than pointer-chasing in a tree.
 */
public final class LongObjectSortedMap<V> {

    private final LongObjectHashMap<V> map;
    private final LongArrayList keys; // always kept in ascending order

    public LongObjectSortedMap() {
        this.map = new LongObjectHashMap<>();
        this.keys = new LongArrayList();
    }

    public V get(long key) {
        return map.get(key);
    }

    public V put(long key, V value) {
        V prev = map.put(key, value);
        if (prev == null) {
            // new key – insert into sorted keys array
            int idx = binarySearch(key);
            if (idx < 0) {
                idx = -idx - 1;
            }
            keys.addAtIndex(idx, key);
        }
        return prev;
    }

    public V remove(long key) {
        V prev = map.remove(key);
        if (prev != null) {
            int idx = binarySearch(key);
            if (idx >= 0) {
                keys.removeAtIndex(idx);
            }
        }
        return prev;
    }

    /**
     * Returns the value associated with the greatest key strictly less than the given key.
     */
    public V getLowerValue(long key) {
        int idx = binarySearch(key);
        if (idx < 0) {
            idx = -idx - 1; // insertion point
        }
        // element before insertion point is the strict predecessor
        if (idx > 0) {
            return map.get(keys.get(idx - 1));
        }
        return null;
    }

    /**
     * Returns the value associated with the smallest key strictly greater than the given key.
     */
    public V getHigherValue(long key) {
        int idx = binarySearch(key);
        if (idx >= 0) {
            idx = idx + 1; // skip the key itself
        } else {
            idx = -idx - 1; // insertion point
        }
        if (idx < keys.size()) {
            return map.get(keys.get(idx));
        }
        return null;
    }

    public int size(int limit) {
        return Math.min(keys.size(), limit);
    }

    public void forEach(BiConsumer<Long, V> procedure, int limit) {
        int n = Math.min(keys.size(), limit);
        for (int i = 0; i < n; i++) {
            long k = keys.get(i);
            procedure.accept(k, map.get(k));
        }
    }

    public void forEachDesc(BiConsumer<Long, V> procedure, int limit) {
        int n = Math.min(keys.size(), limit);
        int last = keys.size() - 1;
        for (int i = 0; i < n; i++) {
            long k = keys.get(last - i);
            procedure.accept(k, map.get(k));
        }
    }

    public void validateInternalState() {
        // simple consistency check (can be expanded if needed)
        if (map.size() != keys.size()) {
            throw new IllegalStateException("Inconsistent state: map.size=" + map.size() + " keys.size=" + keys.size());
        }
        long prev = Long.MIN_VALUE;
        for (int i = 0; i < keys.size(); i++) {
            long k = keys.get(i);
            if (k < prev) {
                throw new IllegalStateException("Keys are not sorted: " + k + " < " + prev);
            }
            prev = k;
            if (!map.containsKey(k)) {
                throw new IllegalStateException("Key missing from map: " + k);
            }
        }
    }

    // manual binary search on the primitive list to avoid boxing
    private int binarySearch(long key) {
        int low = 0;
        int high = keys.size() - 1;
        while (low <= high) {
            int mid = (low + high) >>> 1;
            long midVal = keys.get(mid);
            if (midVal < key) {
                low = mid + 1;
            } else if (midVal > key) {
                high = mid - 1;
            } else {
                return mid;
            }
        }
        return -(low + 1);
    }
}
"}

